options.afterRender:
var root=document.getElementById("ww-root");
if(!root)return;
var container=document.getElementById("ww-spark");
if(!container)return;
var rr=parseFloat(root.dataset.rainRate)||0;

// Live clock
var clockEl=document.getElementById("ww-clock");
if(clockEl){
  function updClock(){
    var n=new Date();
    var pad=function(x){return String(x).padStart(2,"0")};
    clockEl.innerHTML='<span class="ww-clock-time">'+pad(n.getHours())+':'+pad(n.getMinutes())+':'+pad(n.getSeconds())+'</span><span class="ww-clock-date">'+pad(n.getDate())+'.'+pad(n.getMonth()+1)+'.'+String(n.getFullYear()).slice(2)+'</span>';
  }
  updClock();
  if(window.__wwClockId)clearInterval(window.__wwClockId);
  window.__wwClockId=setInterval(updClock,1000);
}

var temp=parseFloat(root.dataset.temp)||0;

var iconEl=document.getElementById("ww-icon");
if(iconEl){
  var svg="";
  if(rr>1){
    svg='<svg width="36" height="36" viewBox="0 0 48 48" fill="none"><path d="M10 28a6 6 0 0 1 6-6h1a8 8 0 0 1 15.3-1.8A6 6 0 0 1 38 26v0a6 6 0 0 1-6 6H16a6 6 0 0 1-6-4z" fill="#8b8fa3" opacity="0.7"/><line x1="16" y1="33" x2="14" y2="39" stroke="#5794f2" stroke-width="1.5" stroke-linecap="round" opacity="0.8"/><line x1="24" y1="33" x2="22" y2="39" stroke="#5794f2" stroke-width="1.5" stroke-linecap="round" opacity="0.8"/><line x1="32" y1="33" x2="30" y2="39" stroke="#5794f2" stroke-width="1.5" stroke-linecap="round" opacity="0.8"/></svg>';
  }else if(rr>0){
    svg='<svg width="36" height="36" viewBox="0 0 48 48" fill="none"><path d="M12 32a7 7 0 0 1 7-7h1a9 9 0 0 1 17.5-2A7 7 0 0 1 38 30v0a7 7 0 0 1-7 7H19a7 7 0 0 1-7-5z" fill="#6b7085" opacity="0.6"/><path d="M8 36a6 6 0 0 1 6-6h1a8 8 0 0 1 15.3-1.8A6 6 0 0 1 36 34v0a6 6 0 0 1-6 6H14a6 6 0 0 1-6-4z" fill="#8b8fa3" opacity="0.8"/></svg>';
  }else{
    var hh=new Date().getHours();
    if(hh>=7&&hh<=19){
      svg='<svg width="36" height="36" viewBox="0 0 48 48" fill="none"><circle cx="18" cy="18" r="8" fill="#f2cc0c" opacity="0.8"/><path d="M16 34a8 8 0 0 1 8-8h4a6 6 0 0 1 6 6v0a6 6 0 0 1-6 6H22a6 6 0 0 1-6-4z" fill="#8b8fa3" opacity="0.7"/></svg>';
    }else{
      svg='<svg width="36" height="36" viewBox="0 0 48 48" fill="none"><path d="M12 32a7 7 0 0 1 7-7h1a9 9 0 0 1 17.5-2A7 7 0 0 1 38 30v0a7 7 0 0 1-7 7H19a7 7 0 0 1-7-5z" fill="#6b7085" opacity="0.6"/><path d="M8 36a6 6 0 0 1 6-6h1a8 8 0 0 1 15.3-1.8A6 6 0 0 1 36 34v0a6 6 0 0 1-6 6H14a6 6 0 0 1-6-4z" fill="#8b8fa3" opacity="0.8"/></svg>';
    }
  }
  iconEl.innerHTML=svg;
}

var tempEl=root.querySelector(".ww-temp");
var degEl=root.querySelector(".ww-deg");
if(tempEl){
  function tempColor(t){var s=[[-10,21,101,192],[0,79,195,247],[10,242,204,12],[20,255,152,48],[30,242,73,92]];if(t<=s[0][0])return"rgb("+s[0][1]+","+s[0][2]+","+s[0][3]+")";if(t>=s[s.length-1][0])return"rgb("+s[s.length-1][1]+","+s[s.length-1][2]+","+s[s.length-1][3]+")";for(var i=0;i<s.length-1;i++){if(t>=s[i][0]&&t<=s[i+1][0]){var f=(t-s[i][0])/(s[i+1][0]-s[i][0]);return"rgb("+Math.round(s[i][1]+(s[i+1][1]-s[i][1])*f)+","+Math.round(s[i][2]+(s[i+1][2]-s[i][2])*f)+","+Math.round(s[i][3]+(s[i+1][3]-s[i][3])*f)+")"}}return"#f2cc0c"}
var tc=tempColor(temp);
  tempEl.style.color=tc;
  if(degEl)degEl.style.color=tc;
}

// Parse hourly: "H:val,H:val,..." where H is local hour (0-23)
var hourlyStr=root.dataset.hourly||"";
if(!hourlyStr){
  container.innerHTML='<div style="color:#5a5e72;font-size:11px;text-align:center;padding:16px">Forecast data loading...</div>';
  return;
}

var pts=[];
var seen={};
var pairs=hourlyStr.split(",");
for(var i=0;i<pairs.length;i++){
  var idx=pairs[i].indexOf(":");
  if(idx>0){
    var hour=parseInt(pairs[i].substring(0,idx),10);
    var val=parseFloat(pairs[i].substring(idx+1));
    if(!isNaN(hour)&&!isNaN(val)&&!seen[hour]){
      seen[hour]=true;
      pts.push({h:hour,v:val});
    }
  }
}
pts.sort(function(a,b){return a.h-b.h});
if(pts.length<2){
  container.innerHTML='<div style="color:#5a5e72;font-size:11px;text-align:center;padding:16px">Not enough forecast data</div>';
  return;
}


// Parse rain hourly data
var rainStr=root.dataset.rainHourly||"";
var rainMap={};
if(rainStr){
  var rPairs=rainStr.split(",");
  for(var i=0;i<rPairs.length;i++){
    var ri=rPairs[i].indexOf(":");
    if(ri>0){
      var rh=parseInt(rPairs[i].substring(0,ri),10);
      var rv=parseFloat(rPairs[i].substring(ri+1));
      if(!isNaN(rh)&&!isNaN(rv))rainMap[rh]=rv;
    }
  }
}
var maxRain=0.1;
for(var k in rainMap){if(rainMap[k]>maxRain)maxRain=rainMap[k]}
var W=container.offsetWidth||480;
var H=80;
var padX=8,padY=14,padBot=14;
var temps=pts.map(function(p){return p.v});
var minV=Math.min.apply(null,temps)-0.5;
var maxV=Math.max.apply(null,temps)+0.5;

// Always span 0-23 for full day
var hMin=0,hMax=23;
function xS(h){return padX+((h-hMin)/(hMax-hMin))*(W-2*padX)}
function yS(v){return padY+((maxV-v)/(maxV-minV))*(H-padY-padBot)}

// Catmull-Rom spline
function crPath(P){
  if(P.length<2)return"";
  var d="M"+xS(P[0].h)+","+yS(P[0].v);
  for(var i=0;i<P.length-1;i++){
    var i0=i>0?i-1:0,i1=i,i2=i+1,i3=i+2<P.length?i+2:P.length-1;
    var x1=xS(P[i1].h),y1=yS(P[i1].v);
    var x2=xS(P[i2].h),y2=yS(P[i2].v);
    d+=" C"+(x1+(xS(P[i2].h)-xS(P[i0].h))/6)+","+(y1+(yS(P[i2].v)-yS(P[i0].v))/6)+" "+(x2-(xS(P[i3].h)-xS(P[i1].h))/6)+","+(y2-(yS(P[i3].v)-yS(P[i1].v))/6)+" "+x2+","+y2;
  }
  return d;
}

var lineD=crPath(pts);
var areaD=lineD+" L"+xS(pts[pts.length-1].h)+","+H+" L"+xS(pts[0].h)+","+H+" Z";

// Now marker (local time)
var now=new Date();
var nowH=now.getHours()+now.getMinutes()/60;
// Interpolate Y
var nowY=0;var nowTemp=pts[0].v;
for(var i=0;i<pts.length-1;i++){
  if(nowH>=pts[i].h&&nowH<=pts[i+1].h){
    var f=(nowH-pts[i].h)/(pts[i+1].h-pts[i].h);
    nowTemp=pts[i].v+(pts[i+1].v-pts[i].v)*f;
    nowY=yS(nowTemp);
    break;
  }
}
if(nowH<=pts[0].h){nowY=yS(pts[0].v);nowTemp=pts[0].v;}
if(nowH>=pts[pts.length-1].h){nowY=yS(pts[pts.length-1].v);nowTemp=pts[pts.length-1].v;}
var nowX=xS(nowH);

// Hour labels every 3h
var labels="";
for(var i=0;i<pts.length;i++){
  if(pts[i].h%3===0){
    labels+='<text x="'+xS(pts[i].h)+'" y="'+(H-2)+'" text-anchor="middle" fill="#5a5e72" font-size="8" font-family="Inter,sans-serif">'+String(pts[i].h).padStart(2,"0")+':00</text>';
  }
}

// Hi/Lo labels
var hiIdx=0,loIdx=0;
for(var i=1;i<pts.length;i++){
  if(pts[i].v>pts[hiIdx].v)hiIdx=i;
  if(pts[i].v<pts[loIdx].v)loIdx=i;
}
var tL='<text x="'+xS(pts[hiIdx].h)+'" y="'+(yS(pts[hiIdx].v)-5)+'" text-anchor="middle" fill="#FF9830" font-size="9" font-weight="600" font-family="Inter,sans-serif">'+pts[hiIdx].v.toFixed(1)+'°</text>';
tL+='<text x="'+xS(pts[loIdx].h)+'" y="'+(yS(pts[loIdx].v)-5)+'" text-anchor="middle" fill="#5794F2" font-size="9" font-weight="600" font-family="Inter,sans-serif">'+pts[loIdx].v.toFixed(1)+'°</text>';


// Rain bars
var rainBars="";
var barSlotW=(W-2*padX)/24;
var barW=barSlotW*0.6;
var rainBarMaxH=(H-padY-padBot)*0.6;
for(var rk in rainMap){
  var rv=rainMap[rk];
  if(rv>0){
    var bH=(rv/maxRain)*rainBarMaxH;
    var bX=xS(parseInt(rk,10))-barW/2;
    var bY=H-padBot-bH;
    var op=(0.15+(rv/maxRain)*0.45).toFixed(2);
    rainBars+='<rect x="'+bX+'" y="'+bY+'" width="'+barW+'" height="'+bH+'" rx="'+(barW/2)+'" fill="#B877D9" opacity="'+op+'"/>';
  }
}


// Parse wind hourly data
var windStr=root.dataset.windHourly||"";
var windPts=[];
var windSeen={};
if(windStr){
  var wPairs=windStr.split(",");
  for(var i=0;i<wPairs.length;i++){
    var wi=wPairs[i].indexOf(":");
    if(wi>0){
      var wh=parseInt(wPairs[i].substring(0,wi),10);
      var wv=parseFloat(wPairs[i].substring(wi+1));
      if(!isNaN(wh)&&!isNaN(wv)&&!windSeen[wh]){
        windSeen[wh]=true;
        windPts.push({h:wh,v:wv});
      }
    }
  }
}
windPts.sort(function(a,b){return a.h-b.h});

// Wind sparkline (blue line with separate Y scale)
var windLine="";
var windDot="";
var windLabels="";
if(windPts.length>=2){
  var wVals=windPts.map(function(p){return p.v});
  var wMin=Math.min.apply(null,wVals);
  var wMax=Math.max.apply(null,wVals);
  if(wMax-wMin<1){wMax=wMin+1}
  var wPadTop=padY+4;
  var wPadBot=padBot+4;
  function yW(v){return wPadTop+((wMax-v)/(wMax-wMin))*(H-wPadTop-wPadBot)}

  // Catmull-Rom for wind
  function crW(P){
    if(P.length<2)return"";
    var d="M"+xS(P[0].h)+","+yW(P[0].v);
    for(var i=0;i<P.length-1;i++){
      var i0=i>0?i-1:0,i1=i,i2=i+1,i3=i+2<P.length?i+2:P.length-1;
      var x1=xS(P[i1].h),y1=yW(P[i1].v);
      var x2=xS(P[i2].h),y2=yW(P[i2].v);
      d+=" C"+(x1+(xS(P[i2].h)-xS(P[i0].h))/6)+","+(y1+(yW(P[i2].v)-yW(P[i0].v))/6)+" "+(x2-(xS(P[i3].h)-xS(P[i1].h))/6)+","+(y2-(yW(P[i3].v)-yW(P[i1].v))/6)+" "+x2+","+y2;
    }
    return d;
  }
  var wLineD=crW(windPts);
  windLine='<path d="'+wLineD+'" fill="none" stroke="#5794F2" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" opacity="0.6"/>';

  // Wind now dot
  var wNowY=0;
  for(var i=0;i<windPts.length-1;i++){
    if(nowH>=windPts[i].h&&nowH<=windPts[i+1].h){
      var f=(nowH-windPts[i].h)/(windPts[i+1].h-windPts[i].h);
      wNowY=yW(windPts[i].v+(windPts[i+1].v-windPts[i].v)*f);
      break;
    }
  }
  if(nowH<=windPts[0].h)wNowY=yW(windPts[0].v);
  if(nowH>=windPts[windPts.length-1].h)wNowY=yW(windPts[windPts.length-1].v);
  windDot='<circle cx="'+nowX+'" cy="'+wNowY+'" r="6" fill="#5794F2" opacity="0.12"/><circle cx="'+nowX+'" cy="'+wNowY+'" r="3" fill="#5794F2" opacity="0.7"/>';

  // Wind hi/lo labels
  var wHiIdx=0,wLoIdx=0;
  for(var i=1;i<windPts.length;i++){
    if(windPts[i].v>windPts[wHiIdx].v)wHiIdx=i;
    if(windPts[i].v<windPts[wLoIdx].v)wLoIdx=i;
  }
  var wHiY=yW(windPts[wHiIdx].v);
  var wLoY=yW(windPts[wLoIdx].v);
  windLabels='<text x="'+xS(windPts[wHiIdx].h)+'" y="'+(wHiY-5)+'" text-anchor="middle" fill="#5794F2" font-size="8" font-weight="600" font-family="Inter,sans-serif" opacity="0.7">'+Math.round(windPts[wHiIdx].v)+'</text>';
  windLabels+='<text x="'+xS(windPts[wLoIdx].h)+'" y="'+(wLoY+12)+'" text-anchor="middle" fill="#5794F2" font-size="8" font-weight="600" font-family="Inter,sans-serif" opacity="0.7">'+Math.round(windPts[wLoIdx].v)+'</text>';
}

var gradStops="";var x0=xS(pts[0].h);var xEnd=xS(pts[pts.length-1].h);var xRange=xEnd-x0;for(var gi=0;gi<pts.length;gi++){var pct=(xRange>0?((xS(pts[gi].h)-x0)/xRange*100):0).toFixed(1);gradStops+='<stop offset="'+pct+'%" stop-color="'+tempColor(pts[gi].v)+'"/>'}
var nowDotColor=tempColor(nowTemp);
container.innerHTML='<svg width="'+W+'" height="'+H+'" style="display:block">'
+'<defs><linearGradient id="tempGrad" x1="'+x0+'" y1="0" x2="'+xEnd+'" y2="0" gradientUnits="userSpaceOnUse">'+gradStops+'</linearGradient></defs>'
+rainBars+windLine+'<path d="'+areaD+'" fill="url(#tempGrad)" fill-opacity="0.15"/>'
+'<path d="'+lineD+'" fill="none" stroke="url(#tempGrad)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>'
+'<line x1="'+nowX+'" y1="'+padY+'" x2="'+nowX+'" y2="'+(H-padBot)+'" stroke="'+nowDotColor+'" stroke-width="0.5" stroke-dasharray="2,2" opacity="0.4"/>'
+'<circle cx="'+nowX+'" cy="'+nowY+'" r="8" fill="'+nowDotColor+'" opacity="0.15"/>'
+'<circle cx="'+nowX+'" cy="'+nowY+'" r="4.5" fill="'+nowDotColor+'"/>'
+windDot+windLabels+tL+labels+'</svg>';

// Solar radiation BlYlRd coloring (0-1000 W/m²)
var solarEl=document.getElementById("ww-solar");
if(solarEl){
  var sr=parseFloat(root.dataset.solarRadiation)||0;
  var sp=Math.min(sr/1000,1);
  var sc;
  if(sp<0.33){var t=sp/0.33;sc="rgb("+Math.round(50+t*205)+","+Math.round(100+t*155)+","+Math.round(200-t*180)+")";}
  else if(sp<0.66){var t=(sp-0.33)/0.33;sc="rgb(255,"+Math.round(255-t*180)+","+Math.round(20+t*10)+")";}
  else{var t=(sp-0.66)/0.34;sc="rgb("+Math.round(255-t*40)+","+Math.round(75-t*50)+",30)";}
  solarEl.style.color=sc;
}

var root=document.getElementById("topo-root");
if(!root)return;
var D={
  prod:parseFloat(root.dataset.prod)||0,
  cons:parseFloat(root.dataset.cons)||0,
  soc:parseFloat(root.dataset.soc)||0,
  bat:parseFloat(root.dataset.bat)||0,
  meter:parseFloat(root.dataset.meter)||0,
  charge:parseFloat(root.dataset.charge)||0,
  carConn:parseFloat(root.dataset.carConn)||0,
  lp1:parseFloat(root.dataset.loadP1)||0,
  lp2:parseFloat(root.dataset.loadP2)||0,
  lp3:parseFloat(root.dataset.loadP3)||0,
  invTemp:parseFloat(root.dataset.invTemp)||0
};

// Phase color by kW tier
function phaseColor(kw){
  if(kw>3)return"#f2495c";
  if(kw>2)return"#FF9830";
  if(kw>1)return"#FADE2A";
  return"#73bf69";
}
var l1=document.getElementById("topo-phase-l1");
var l2=document.getElementById("topo-phase-l2");
var l3=document.getElementById("topo-phase-l3");
if(l1)l1.setAttribute("fill",phaseColor(D.lp1));
if(l2)l2.setAttribute("fill",phaseColor(D.lp2));
if(l3)l3.setAttribute("fill",phaseColor(D.lp3));

// Temperature color
var tEl=document.getElementById("topo-temp-val");
if(tEl){
  var tc=D.invTemp<=40?"#73bf69":D.invTemp<=50?"#FADE2A":D.invTemp<=60?"#FF9830":"#f2495c";
  tEl.setAttribute("fill",tc);
}

// Solar arrow
var arrS=document.getElementById("topo-arr-solar");
if(arrS){
  if(D.prod>0.1){
    var sw=Math.min(2+D.prod*1.5,12);
    arrS.setAttribute("stroke-width",sw);
    arrS.setAttribute("stroke-opacity","1");
    arrS.setAttribute("stroke-dasharray","10 6");
    arrS.classList.add("flow-solar");
  }
}

// Grid arrow
var arrG=document.getElementById("topo-arr-grid");
if(arrG){
  var mAbs=Math.abs(D.meter);
  if(mAbs>0.1){
    var gw=Math.min(2+mAbs*1.5,12);
    arrG.setAttribute("stroke-width",gw);
    arrG.setAttribute("stroke-opacity","1");
    arrG.setAttribute("stroke-dasharray","10 6");
    if(D.meter>0){
      arrG.setAttribute("d","M400,140 L222,149");
      arrG.setAttribute("stroke","#73bf69");
      arrG.setAttribute("marker-end","url(#arr-green)");
    }else{
      arrG.setAttribute("stroke","#f2495c");
      arrG.setAttribute("marker-end","url(#arr-muted)");
    }
  }
}

// Battery arrow
var arrB=document.getElementById("topo-arr-bat");
if(arrB){
  var bAbs=Math.abs(D.bat);
  if(bAbs>0.1){
    var bw=Math.min(2+bAbs*1.5,12);
    arrB.setAttribute("stroke-width",bw);
    arrB.setAttribute("stroke-opacity","1");
    arrB.setAttribute("stroke-dasharray","10 6");
    arrB.classList.add("flow-batt");
    if(D.bat>0){
      arrB.setAttribute("d","M940,52 L762,72");
    }
  }
}

// House arrow
var arrH=document.getElementById("topo-arr-house");
if(arrH){
  if(D.cons>0.1){
    var hw=Math.min(2+D.cons*1.2,10);
    arrH.setAttribute("stroke-width",hw);
    arrH.setAttribute("stroke-opacity","1");
    arrH.setAttribute("stroke-dasharray","7 4");
    arrH.classList.add("flow-house");
  }
}

// Wallbox arrow
var arrW=document.getElementById("topo-arr-wb");
if(arrW&&D.charge>0.1){
  var ww=Math.min(2+D.charge*1.5,12);
  arrW.setAttribute("stroke-width",ww);
  arrW.setAttribute("stroke-opacity","1");
  arrW.setAttribute("stroke","#FF9830");
  arrW.setAttribute("marker-end","url(#arr-yellow)");
}

// Solar ladder bars
var solarBars=document.querySelectorAll("#topo-solar-bars rect");
if(solarBars.length===20){
  var nLit=Math.floor(D.prod*2);
  for(var i=0;i<20;i++){
    solarBars[i].setAttribute("opacity",i<nLit?"0.5":"0.14");
  }
}

// Battery SoC bars
var batBars=document.querySelectorAll("#topo-bat-bars rect");
if(batBars.length===20){
  var nBat=Math.floor(D.soc/5);
  var batCol=D.soc>90?"#5794F2":D.soc>=30?"#73BF69":D.soc>=20?"#FF9830":D.soc>=10?"#FF6B3D":"#F2495C";
  var batG=document.getElementById("topo-bat-bars");
  if(batG)batG.setAttribute("fill",batCol);
  for(var i=0;i<20;i++){
    batBars[i].setAttribute("opacity",i<nBat?"0.4":"0.14");
  }
}

// House consumption bars
var houseBars=document.querySelectorAll("#topo-house-bars rect");
if(houseBars.length===20){
  var nH=Math.floor(D.cons*2);
  for(var i=0;i<20;i++){
    houseBars[i].setAttribute("opacity",i<nH?"0.5":"0.14");
  }
}

// Wallbox bars
var wbBars=document.querySelectorAll("#topo-wb-bars rect");
if(wbBars.length===20){
  var nW=Math.floor(D.charge*2);
  for(var i=0;i<20;i++){
    wbBars[i].setAttribute("opacity",i<nW?"0.5":"0.14");
  }
}

// Battery SoC text color
var socEl=document.getElementById("topo-bat-soc");
if(socEl){
  var sColor=D.soc>90?"#5794F2":D.soc>=30?"#73BF69":D.soc>=20?"#FF9830":D.soc>=10?"#FF6B3D":"#F2495C";
  socEl.setAttribute("fill",sColor);
}

// Grid diverging bars
var gridBars=document.querySelectorAll("#topo-grid-bars rect");
if(gridBars.length===20){
  var mKw=D.meter;
  if(mKw>0.1){
    var nExp=Math.min(Math.floor(mKw),10);
    for(var i=0;i<10;i++){gridBars[9-i].setAttribute("opacity",i<nExp?"0.5":"0.14");}
    for(var i=10;i<20;i++){gridBars[i].setAttribute("opacity","0.14");}
  }else if(mKw<-0.1){
    var nImp=Math.min(Math.floor(Math.abs(mKw)),10);
    for(var i=0;i<10;i++){gridBars[i].setAttribute("opacity","0.14");}
    for(var i=0;i<nImp;i++){gridBars[10+i].setAttribute("opacity","0.5");}
  }
}

options.helpers:
handlebars.registerHelper("lt", function(a, b) { return parseFloat(a) < parseFloat(b); });
handlebars.registerHelper("gt", function(a, b) { return parseFloat(a) > parseFloat(b); });
handlebars.registerHelper("gte", function(a, b) { return parseFloat(a) >= parseFloat(b); });
handlebars.registerHelper("abs", function(a) { return Math.abs(parseFloat(a)); });

options.afterRender:
var root=document.getElementById("estat-root");
if(!root)return;
var dc=parseFloat(root.dataset.dCons)||0,dg=parseFloat(root.dataset.dGen)||0;
var mc=parseFloat(root.dataset.mCons)||0,mg=parseFloat(root.dataset.mGen)||0;

function setBars(consId,prodId,deltaId,c,g){
  var mx=Math.max(c,g,0.1);
  var cb=document.getElementById(consId),gb=document.getElementById(prodId);
  if(cb)cb.style.width=(c/mx*100)+"%";
  if(gb)gb.style.width=(g/mx*100)+"%";
  var dd=document.getElementById(deltaId);
  if(dd){
    var delta=g-c;
    var sign=delta>=0?"+":"";
    var color=delta>=0?"#73bf69":"#f2495c";
    dd.innerHTML='<span style="color:'+color+'">'+sign+delta.toFixed(1)+'<span class="unit"> kWh</span></span>';
  }
}
setBars("estat-d-cons-bar","estat-d-prod-bar","estat-d-delta",dc,dg);
setBars("estat-m-cons-bar","estat-m-prod-bar","estat-m-delta",mc,mg);

